let $brandPart := 
  if (exists($input.Product_Brand ) and string-length(normalize-space($input.Product_Brand )) > 0)
  then
    concat('"p360item.brand": "', 
           replace($input.Product_Brand , '"', '\\"'), '"')
  else ()

let $descPart := 
  if (exists($input.Product_Description ) and string-length(normalize-space($input.Product_Description )) > 0)
  then
    concat((:'"p360item.description.longDescription": "', 
           replace($input.Product_Description , '"', '\\"'), '*", ',:)
