let $fields :=
if ($brandPart and $descPart and $gtinPart and $identifierPart)
then concat($brandPart, ', ', $descPart, ', ', $gtinPart, ', ', $identifierPart)
else if ($brandPart and $descPart and $gtinPart)
then concat($brandPart, ', ', $descPart, ', ', $gtinPart)
else if ($brandPart and $descPart and $identifierPart)
then concat($brandPart, ', ', $descPart, ', ', $identifierPart)
else if ($brandPart and $gtinPart and $identifierPart)
then concat($brandPart, ', ', $gtinPart, ', ', $identifierPart)
else if ($descPart and $gtinPart and $identifierPart)
then concat($descPart, ', ', $gtinPart, ', ', $identifierPart)
else if ($brandPart and $descPart)
then concat($brandPart, ', ', $descPart)
else if ($brandPart and $gtinPart)
then concat($brandPart, ', ', $gtinPart)
else if ($brandPart and $identifierPart)
then concat($brandPart, ', ', $identifierPart)
else if ($descPart and $gtinPart)
then concat($descPart, ', ', $gtinPart)
else if ($descPart and $identifierPart)
then concat($descPart, ', ', $identifierPart)
else if ($gtinPart and $identifierPart)
then concat($gtinPart, ', ', $identifierPart)
else if ($brandPart)
then $brandPart
else if ($descPart)
then $descPart
else if ($gtinPart)
then $gtinPart
else if ($identifierPart)
then $identifierPart
else ()


return 
  if (empty($fields))
  then ()
  else
    concat(
      '{',
      '"entityType": "p360.item",',
      '"fields": {', 
      $fields, 
      '},',
      '"recordsToReturn": ',$input.NumberOfRecordsReturn ,'',
      '}'
    )

