let $Item_Response:= $output.SearchAPI_Response 
(: Inline approach checking against constructed paths :)
let $nameMapXML := $temp.tmp_Entity1_map_Fields 
(: Helper to check if full local-name path is excluded :)
let $excludeXML := $temp.tmp_Entity1_Exclude_Fields 
(: Start processing root element children :)
return
if ( $Item_Response//hits/text() = 0) then
  'No Records Found'
else
  <root>{
    for $record in $Item_Response//records
    return
      <records>{

        (: level 1 :)
        for $child1 in $record/*
        let $name1 := name($child1)
        let $path1 := $name1
        where not(some $ex in $excludeXML/item satisfies $ex = $path1)
        return element {
          let $map1 := $nameMapXML/mapEntry[@key = $name1]
          return if (exists($map1)) then string($map1) else $name1
        } {
          if ($child1/*) then (

            (: level 2 :)
            for $child2 in $child1/*
            let $name2 := name($child2)
            let $path2 := concat($path1, '/', $name2)
            where not(some $ex in $excludeXML/item satisfies $ex = $path2)
            return element {
              let $map2 := $nameMapXML/mapEntry[@key = concat($name1, '.', $name2)]
              return if (exists($map2)) then string($map2) else $name2
            } {
              if ($child2/*) then (

                (: level 3 :)
                for $child3 in $child2/*
                let $name3 := name($child3)
                let $path3 := concat($path2, '/', $name3)
                where not(some $ex in $excludeXML/item satisfies $ex = $path3)
                return element {
                  let $map3 := $nameMapXML/mapEntry[@key = concat($name1, '.', $name2, '.', $name3)]
                  return if (exists($map3)) then string($map3) else $name3
                } {
                  if ($child3/*) then (

                    (: level 4 :)
                    for $child4 in $child3/*
                    let $name4 := name($child4)
                    let $path4 := concat($path3, '/', $name4)
                    where not(some $ex in $excludeXML/item satisfies $ex = $path4)
                    return element {
                      let $map4 := $nameMapXML/mapEntry[@key = concat($name1, '.', $name2, '.', $name3, '.', $name4)]
                      return if (exists($map4)) then string($map4) else $name4
                    } { $child4/node() }

                  )
                  else $child3/node()
                }
              )
              else $child2/node()
            }
          )
          else $child1/node()

      },

      (: Prepare businessId element if not excluded :)
      let $businessIdPath := '_meta/businessId'
      where not(some $ex in $excludeXML/item satisfies $ex = $businessIdPath)
      return element {
        let $mapB := $nameMapXML/mapEntry[@key='businessId']
        return if (exists($mapB)) then string($mapB) else 'businessId'
      } { $record/_meta/businessId/text() },

      (: entityType :)
      let $entityTypePath := '_meta/entityType'
      let $entityTypeValue := 'Item'
      where not(some $ex in $excludeXML/item satisfies $ex = $entityTypePath)
      return
        if (exists($entityTypeValue)) then
          element {
            let $mapE := $nameMapXML/mapEntry[@key='entityType']
            return if (exists($mapE)) then string($mapE) else 'entityType'
          } { $entityTypeValue }
        else ()
  }</records>
  }</root>
